const Web3 = require('web3');
const ethers = require('ethers');

// Initialize web3 and ethers instances
const web3 = new Web3(new Web3.providers.HttpProvider('https://mainnet.infura.io/v3/YOUR_API_KEY'));
const ethersInstance = new ethers.Wallet(process.env.PRIVATE_KEY, web3);

// Function to send ETH transactions
async function sendETHTransaction(recipientAddress, amount) {
  const tx = {
    from: ethersInstance.getAddress(),
    to: recipientAddress,
    value: ethers.utils.parseEther(amount),
  };
  return await web3.eth.sendTransaction(tx);
}

// Function to interact with smart contracts
async function interactWithSmartContract(contractAddress, abi, methodName, args) {
  const contract = new ethersInstance.Contract(contractAddress, abi, {
    from: ethersInstance.getAddress(),
  });
  return await contract[methodName](...args);
}

// Wallet configuration with private keys for signing transactions
const walletConfig = {
  privateKey: process.env.PRIVATE_KEY,
};

// Export functions for use in the DApp backend service
module.exports = {
  sendETHTransaction,
  interactWithSmartContract,
  walletConfig,
};